// Keep this in sync with docs/ai-memory/core-philosophy.json — this node embeds a copy
// (same pragmatic approach the existing openthai-ai-automation.json workflow uses for its
// hardcoded LINE templates). If core-philosophy.json changes, update this node's code too,
// then re-import this workflow. See docs/ai-memory/INTEGRATION_GUIDE.md, Option C.
const core = {
  id: 'openthaiai-core-philosophy-v1',
  version: '1.0.0',
  core_philosophy: {
    statement: 'Ground truth over narrative confidence. A claim about this project\'s architecture, features, or state — no matter which AI assistant produced it, no matter how confident or detailed it sounds — is only as good as its citation to the real repository (source code, migrations, git log, deployed behavior). When a claim and the repo disagree, the repo wins.',
    one_line: 'Verify against the repo. Every time. No exception for confidence or detail.'
  },
  key_lessons: [
    {
      id: 'lesson_01_verify_before_build',
      title: 'Verify scope against the real repo before implementing pasted content',
      statement: 'Before implementing any specification pasted from another AI conversation, grep the actual repository for the classes, tables, and env vars it claims exist. If they don\'t exist, pause and confirm scope with the human before building.',
      evidence: ['DECISIONS_LOG.md — Rejected: Neo4j graph database', 'DECISIONS_LOG.md — Rejected: cross-border USD/Stripe/PCI-DSS escrow platform']
    },
    {
      id: 'lesson_02_derive_dont_hardcode',
      title: 'A single source of truth must be derived from code, never hand-typed',
      statement: 'Any status/context document meant to keep multiple readers aligned must be generated by parsing the real repository, not hand-maintained as a static summary that can silently drift from reality.',
      evidence: ['scripts/generate-project-status.mjs replacing the hardcoded daily-briefing.sh']
    },
    {
      id: 'lesson_03_fairness_both_sides',
      title: 'Fairness requires hearing and notifying both sides before deciding',
      statement: 'Any process that adjudicates between two parties must give both sides visibility and a chance to respond before a decision is finalized, not just the side that triggered the workflow.',
      evidence: ['backend/disputes.js respond() and track()', 'sendDisputeNotification() now emails both parties']
    }
  ]
};

const items = [];
items.push({ json: { text: core.core_philosophy.statement, type: 'philosophy', metadata: { source_id: core.id, version: core.version } } });
for (const lesson of core.key_lessons) {
  items.push({ json: { text: `${lesson.title}: ${lesson.statement}`, type: 'lesson', metadata: { lesson_id: lesson.id, evidence: lesson.evidence } } });
}
return items;
